mapper.select:
SELECT * FROM lesson
WHERE user_id = #{userId}
ORDER BY created_at DESC

mapper.insert:
INSERT INTO lesson (
    id, user_id, subject_id, title, description, status, price, field_id
) VALUES (
    UUID(), #{userId}, #{subjectId}, #{title}, #{description}, 'OPEN', #{price}, #{fieldId}
)

mapper.update:
UPDATE lesson
SET status = #{status}
WHERE id = #{id}
